    /* 7C6390 802ECE00 */ .asciz "\\BOh! Hi, %s!\nWhat a surprise to see you here!"
    /* 5C424F68212048692C202573210A57686174206120737572707269736520746F2073656520796F752068657265210000 */
.align 2
.align 2
    /* 7C63C0 802ECE30 */ .asciz "I suppose you'd like to\nknow why I am here?\nAhh, well..."
    /* 4920737570706F736520796F752764206C696B6520746F0A6B6E6F7720776879204920616D20686572653F0A4168682C2077656C6C2E2E2E00000000 */
.align 2
.align 2
    /* 7C63FC 802ECE6C */ .asciz "I received some interesting\ninformation at\nthe Pokεmon Lab."
    /* 4920726563656976656420736F6D6520696E746572657374696E670A696E666F726D6174696F6E2061740A74686520506F6BA6C56D6F6E204C61622E00000000 */
.align 2
.align 2
    /* 7C643C 802ECEAC */ .asciz "It seems that there are six\nPKMN Signs hidden on this\nisland."
    /* 4974207365656D73207468617420746865726520617265207369780A504B4D4E205369676E732068696464656E206F6E20746869730A69736C616E642E000000 */
.align 2
.align 2
    /* 7C647C 802ECEEC */ .asciz "They have something to do\nwith important Pokεmon\nthat are here."
    /* 54686579206861766520736F6D657468696E6720746F20646F0A7769746820696D706F7274616E7420506F6BA6C56D6F6E0A746861742061726520686572652E00000000 */
.align 2
.align 2
    /* 7C64C0 802ECF30 */ .asciz "The Signs are scenery which\nseem to resemble Pokεmon."
    /* 546865205369676E7320617265207363656E6572792077686963680A7365656D20746F20726573656D626C6520506F6BA6C56D6F6E2E0000 */
.align 2
.align 2
    /* 7C64F8 802ECF68 */ .asciz "One Sign is a mountain that\nlooks like DUGTRIO. I came\nhere to look for it."
    /* 4F6E65205369676E2069732061206D6F756E7461696E20746861740A6C6F6F6B73206C696B65204455475452494F2E20492063616D650A6865726520746F206C6F6F6B20666F722069742E00 */
.align 2
.align 2
    /* 7C6544 802ECFB4 */ .asciz "However, I can't go any\ndeeper into the island,\nso I can't find it."
    /* 486F77657665722C20492063616E277420676F20616E790A64656570657220696E746F207468652069736C616E642C0A736F20492063616E27742066696E642069742E00 */
.align 2
.align 2
    /* 7C6588 802ECFF8 */ .asciz "Have you seen a mountain that\nlooks like DUGTRIO?\nOh! I have an idea!"
    /* 4861766520796F75207365656E2061206D6F756E7461696E20746861740A6C6F6F6B73206C696B65204455475452494F3F0A4F68212049206861766520616E206964656121000000 */
.align 2
.align 2
    /* 7C65D0 802ED040 */ .asciz "If you find this PKMN Sign,\ntake a picture of it like you\nwould a Pokεmon."
    /* 496620796F752066696E64207468697320504B4D4E205369676E2C0A74616B6520612070696374757265206F66206974206C696B6520796F750A776F756C64206120506F6BA6C56D6F6E2E00 */
.align 2
.align 2
    /* 7C661C 802ED08C */ .asciz "We might discover clues from\nthe pictures and the places\nwhere you took them."
    /* 5765206D6967687420646973636F76657220636C7565732066726F6D0A74686520706963747572657320616E642074686520706C616365730A776865726520796F7520746F6F6B207468656D2E000000 */
.align 2
.align 2
    /* 7C666C 802ED0DC */ .asciz "Shall I repeat this information?\n\\a Yes, please.\n\\b No, thank you."
    /* 5368616C6C204920726570656174207468697320696E666F726D6174696F6E3F0A5C61205965732C20706C656173652E0A5C62204E6F2C207468616E6B20796F752E0000 */
.align 2
.align 2
    /* 7C66B0 802ED120 */ .asciz "\\QWait...\nI will add a page for PKMN Signs\nin the PKMN Report."
    /* 5C51576169742E2E2E0A492077696C6C206164642061207061676520666F7220504B4D4E205369676E730A696E2074686520504B4D4E205265706F72742E0000 */
.align 2
.align 2
